codeExample:
fruits = {"apple", "banana", "cherry"}

# Simple loop
print("Items:")
for fruit in fruits:
    print(fruit)

# Sorted loop
print("\nSorted:")
for fruit in sorted(fruits):
    print(fruit)

# List comprehension
numbers = {1, 2, 3, 4, 5}
squares = [x**2 for x in numbers]
print("\nSquares:", squares)
